package com.lugatek.thubanlodestar.widgets;
import android.content.*;import android.graphics.*;import android.util.*;import android.view.*;import java.util.*;
public class LineGraphView extends View{ Paint p=new Paint(1),grid=new Paint(1); ArrayList<Float> vals=new ArrayList<>(); public LineGraphView(Context c){super(c);init();} public LineGraphView(Context c,AttributeSet a){super(c,a);init();} void init(){p.setColor(Color.rgb(0,220,255));p.setStrokeWidth(4);p.setStyle(Paint.Style.STROKE);grid.setColor(Color.rgb(55,66,82));grid.setStrokeWidth(1);} public void add(float v){vals.add(v);while(vals.size()>120)vals.remove(0);invalidate();} protected void onDraw(Canvas c){super.onDraw(c);c.drawColor(Color.rgb(18,24,33));int w=getWidth(),h=getHeight();for(int i=1;i<4;i++)c.drawLine(0,h*i/4,w,h*i/4,grid);if(vals.size()<2)return;float max=1;for(float v:vals)max=Math.max(max,Math.abs(v));Path path=new Path();for(int i=0;i<vals.size();i++){float x=w*(i/(float)(vals.size()-1));float y=h/2-(vals.get(i)/max)*(h*.42f);if(i==0)path.moveTo(x,y);else path.lineTo(x,y);}c.drawPath(path,p);} }
